import React, { useState, useEffect } from "react";

export default function Profile() {
  const [user, setUser] = useState({
    name: "",
    email: "",
    phone: "",
    vehiclenumber: "",
  });

  useEffect(() => {
    // Fetch user details when the component mounts
    const fetchUserData = async () => {
      const token = localStorage.getItem("authToken");
      if (!token) return;

      try {
        const response = await fetch(
          `${process.env.REACT_APP_API_BASE_URL}/users/profile`,
          {
            method: "GET",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${token}`,
            },
          }
        );

        const data = await response.json();
        if (response.ok) {
          setUser({
            name: data.name,
            email: data.email,
            phone: data.phone,
            vehiclenumber: data.vehiclenumber,
          });

          // Store updated user info in localStorage
          localStorage.setItem("user", JSON.stringify(data));
        } else {
          console.error("Error fetching user data:", data.message);
        }
      } catch (error) {
        console.error("Error fetching user data:", error);
      }
    };

    fetchUserData();
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setUser({ ...user, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const token = localStorage.getItem("authToken");
    if (!token) return;

    try {
      const response = await fetch(
        `${process.env.REACT_APP_API_BASE_URL}/users/update-profile`,
        {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify(user),
        }
      );

      const data = await response.json();
      if (response.ok) {
        alert("Profile updated successfully!");

        // Update localStorage with new user data
        localStorage.setItem("user", JSON.stringify(user));

        // Refresh UI where username is displayed
        window.dispatchEvent(new Event("storage"));
      } else {
        alert(`Error: ${data.message}`);
      }
    } catch (error) {
      console.error("Error updating profile:", error);
    }
  };

  return (
    <div className="bg-white border border-4 rounded-lg shadow relative m-10 p-6">
      <h3 className="text-xl font-semibold mb-4">Edit Profile</h3>
      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-900">
              Employee Name
            </label>
            <input
              type="text"
              name="name"
              value={user.name}
              onChange={handleChange}
              className="mt-2 block w-full rounded-md bg-gray-50 border border-gray-300 p-2.5 text-gray-900"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-900">
              Employee Email Address
            </label>
            <input
              type="email"
              name="email"
              value={user.email}
              onChange={handleChange}
              className="mt-2 block w-full rounded-md bg-gray-50 border border-gray-300 p-2.5 text-gray-900"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-900">
              Mobile Number
            </label>
            <input
              type="text"
              name="phone"
              value={user.phone}
              onChange={handleChange}
              className="mt-2 block w-full rounded-md bg-gray-50 border border-gray-300 p-2.5 text-gray-900"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-900">
              Vehicle Number
            </label>
            <input
              type="text"
              name="vehiclenumber"
              value={user.vehiclenumber}
              onChange={handleChange}
              className="mt-2 block w-full rounded-md bg-gray-50 border border-gray-300 p-2.5 text-gray-900"
            />
          </div>
        </div>

        <button
          type="submit"
          className="mt-4 text-white bg-cyan-600 hover:bg-cyan-700 px-5 py-2.5 rounded-lg text-sm font-medium"
        >
          Save Changes
        </button>
      </form>
    </div>
  );
}
